import { useEffect, useState } from 'react';
import API from '../api/axios';

const statusColor = { pending: '#f59e0b', confirmed: '#10b981', cancelled: '#ef4444', completed: '#6366f1' };

export default function MyAppointments() {
  const [appointments, setAppointments] = useState([]);

  useEffect(() => {
    API.get('/appointments/my').then(res => setAppointments(res.data));
  }, []);

  const handleCancel = async (id) => {
    await API.put(`/appointments/${id}/status`, { status: 'cancelled' });
    setAppointments(prev => prev.map(a => a._id === id ? { ...a, status: 'cancelled' } : a));
  };

  return (
    <div style={styles.container}>
      <h2 style={styles.title}>My Appointments</h2>
      {appointments.length === 0 && <p>No appointments found.</p>}
      {appointments.map(a => (
        <div key={a._id} style={styles.card}>
          <div style={styles.row}>
            <h3 style={styles.service}>{a.service?.name}</h3>
            <span style={{ ...styles.badge, background: statusColor[a.status] }}>
              {a.status}
            </span>
          </div>
          <p>📅 {a.date} &nbsp; ⏰ {a.timeSlot}</p>
          <p>👤 Provider: {a.provider?.name}</p>
          {a.notes && <p>📝 {a.notes}</p>}
          {a.status === 'pending' && (
            <button style={styles.cancelBtn} onClick={() => handleCancel(a._id)}>
              Cancel
            </button>
          )}
        </div>
      ))}
    </div>
  );
}

const styles = {
  container: { padding: '30px 40px', background: '#f0f4ff', minHeight: '90vh' },
  title: { color: '#1a73e8', marginBottom: '20px' },
  card: { background: '#fff', padding: '20px', borderRadius: '12px', marginBottom: '16px', boxShadow: '0 2px 10px rgba(0,0,0,0.07)' },
  row: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  service: { color: '#333', margin: 0 },
  badge: { color: '#fff', padding: '4px 12px', borderRadius: '20px', fontSize: '13px' },
  cancelBtn: { marginTop: '10px', background: '#ef4444', color: '#fff', border: 'none', padding: '8px 16px', borderRadius: '8px', cursor: 'pointer' }
};
